# ---- MFA Setup ----

@app.route('/mfa/setup', methods=['GET', 'POST'])
@login_required
def mfa_setup():
    """MFA setup page for enabling/configuring MFA."""
    username = session.get('username')
    user = USERS.get(username)

    if not user:
        return redirect(url_for('login_page'))

    # Generate new secret if not exists
    if not user.get('mfa_secret'):
        user['mfa_secret'] = base64.b32encode(os.urandom(20)).decode('utf-8')

    mfa_secret = user['mfa_secret']
    current_code = generate_totp(mfa_secret)

    if request.method == 'GET':
        return render_template_string(
            MFA_SETUP_TEMPLATE,
            mfa_secret=mfa_secret,
            current_code=current_code,
            error=None,
            success=None
        )

    mfa_code = request.form.get('mfa_code', '').strip()

    if verify_totp(mfa_secret, mfa_code):
        user['mfa_enabled'] = True
        session['mfa_verified'] = True
        session['mfa_pending'] = False
        session['mfa_verified_time'] = time.time()
        return render_template_string(
            MFA_SETUP_TEMPLATE,
            mfa_secret=mfa_secret,
            current_code=generate_totp(mfa_secret),
            error=None,
            success='MFA has been successfully enabled! Your account is now more secure.'
        )
    else:
        return render_template_string(
            MFA_SETUP_TEMPLATE,
            mfa_secret=mfa_secret,
            current_code=generate_totp(mfa_secret),
            error='Invalid code. Please try again.',
            success=None
        ), 400


@app.route('/mfa/disable', methods=['POST'])
@mfa_required
def mfa_disable():
    """Disable MFA (requires current MFA verification)."""
    username = session.get('username')
    user = USERS.get(username)

    if user:
        user['mfa_enabled'] = False
        session['mfa_verified'] = True
        session['mfa_pending'] = False
        return jsonify({'message': 'MFA has been disabled', 'username': username})

    return jsonify({'error': 'User not found'}), 404


# ---- Background MFA Verification API ----

@app.route('/api/verify-mfa-background', methods=['POST'])
@login_required
def verify_mfa_background():
    """
    Background MFA verification endpoint.
    Allows the frontend to verify MFA asynchronously without page reload.
    This is the key endpoint for background MFA verification UX.
    """
    username = session.get('username')
    user = USERS.get(username)

    if not user or not user.get('mfa_enabled'):
        session['mfa_verified'] = True
        session['mfa_pending'] = False
        return jsonify({'status': 'success', 'message': 'MFA not required'})

    data = request.get_json() or {}
    mfa_code = data.get('mfa_code', '').strip()

    if not mfa_code:
        return jsonify({'status': 'error', 'message': 'MFA code required'}), 400

    if verify_totp(user['mfa_secret'], mfa_code):
        session['mfa_verified'] = True
        session['mfa_pending'] = False
        session['mfa_verified_time'] = time.time()
        return jsonify({
            'status': 'success',
            'message': 'MFA verified successfully',
            'access_level': 'full'
        })
    else:
        return jsonify({
            'status': 'error',
            'message': 'Invalid MFA code'
        }), 401


